// Renders the Trello-style board from board.json (generated by `npm run build`).
// When served by the local server (npm run serve), dragging a card calls the
// write API to update the Jira label: it removes the source column's label and
// adds the target column's label.

const boardEl = document.getElementById("board");
const updatedEl = document.getElementById("updated");
const searchEl = document.getElementById("search");
const editBadge = document.getElementById("edit-badge");
const addColForm = document.getElementById("add-column-form");
const addColInput = document.getElementById("add-column-input");

let editable = false;
let dragged = null; // { el, issueKey }
let dragEndedAt = 0;

function el(tag, props = {}, children = []) {
  const node = document.createElement(tag);
  const { dataset, ...rest } = props;
  Object.assign(node, rest);
  for (const [k, v] of Object.entries(dataset || {})) node.dataset[k] = v;
  for (const child of [].concat(children)) if (child != null) node.append(child);
  return node;
}

// Real Jira label for a column, or null for the Uncategorized / no-label bucket.
function labelOf(colEl) {
  const l = colEl?.dataset.label;
  return l ? l : null;
}

function showToast(message, isError = false) {
  const t = el("div", { className: "toast" + (isError ? " error" : ""), textContent: message });
  document.body.append(t);
  setTimeout(() => t.remove(), isError ? 5000 : 2500);
}

function updateCount(colEl) {
  const n = colEl.querySelectorAll(".card").length;
  colEl.querySelector(".count").textContent = String(n);
}

/* ---------------- rendering ---------------- */

function renderCard(issue) {
  const summary = el("p", { className: "card-summary", textContent: issue.summary });
  const key = el("span", { className: "card-key", textContent: issue.key });
  const status = el("span", {
    className: "status",
    textContent: issue.status,
    dataset: { cat: issue.statusCategory },
  });

  const footerChildren = [key, status];
  if (issue.assigneeAvatar) {
    footerChildren.push(
      el("img", {
        className: "assignee",
        src: issue.assigneeAvatar,
        alt: issue.assignee || "",
        title: issue.assignee || "",
        loading: "lazy",
      })
    );
  }
  const footer = el("div", { className: "card-footer" }, footerChildren);

  const card = el(
    "a",
    {
      className: "card",
      href: issue.url,
      target: "_blank",
      rel: "noopener",
      draggable: editable,
      dataset: { cat: issue.statusCategory, key: issue.key },
    },
    [summary, footer]
  );
  card._search = `${issue.key} ${issue.summary} ${issue.status} ${issue.assignee || ""}`.toLowerCase();
  return card;
}

function makeColumn({ label, display, issues = [], uncategorized = false }) {
  const header = el("div", { className: "column-header" }, [
    el("span", { textContent: display ?? label }),
    el("span", { className: "count", textContent: String(issues.length) }),
  ]);
  const cards = el("div", { className: "cards" }, issues.map(renderCard));
  const col = el("div", {
    className: "column",
    dataset: { label: uncategorized ? "" : label },
  }, [header, cards]);

  if (editable) wireDropTarget(col);
  return col;
}

function existingColumnLabels() {
  return new Set(
    [...boardEl.querySelectorAll(".column")].map((c) => labelOf(c)).filter(Boolean)
  );
}

/* ---------------- drag & drop ---------------- */

function wireDropTarget(col) {
  const cards = col.querySelector(".cards");
  col.addEventListener("dragover", (e) => {
    if (!dragged) return;
    e.preventDefault();
    col.classList.add("drag-over");
  });
  col.addEventListener("dragleave", (e) => {
    if (!col.contains(e.relatedTarget)) col.classList.remove("drag-over");
  });
  col.addEventListener("drop", (e) => {
    e.preventDefault();
    col.classList.remove("drag-over");
    if (dragged) onDrop(col, cards);
  });
}

function onDragStart(card, e) {
  dragged = { el: card, issueKey: card.dataset.key };
  card.classList.add("dragging");
  // Prevent the anchor from navigating; we still allow click-to-open when not dragging.
  e.dataTransfer.effectAllowed = "move";
  e.dataTransfer.setData("text/plain", card.dataset.key);
}

function onDragEnd(card) {
  card.classList.remove("dragging");
  dragged = null;
  dragEndedAt = performance.now();
}

async function onDrop(targetCol, targetCardsEl) {
  const card = dragged.el;
  const issueKey = dragged.issueKey;
  const sourceCol = card.closest(".column");
  const fromLabel = labelOf(sourceCol);
  const toLabel = labelOf(targetCol);

  if (sourceCol === targetCol || fromLabel === toLabel) return;

  // If the target column already shows this issue, moving here would duplicate it.
  const dupe = [...targetCardsEl.querySelectorAll(".card")].find(
    (c) => c.dataset.key === issueKey
  );

  card.classList.add("saving");
  try {
    const res = await fetch("/api/move", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ issueKey, fromLabel, toLabel }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);

    if (dupe) {
      card.remove(); // already present in target — just drop the source copy
    } else {
      targetCardsEl.append(card);
    }
    updateCount(sourceCol);
    updateCount(targetCol);
    showToast(
      `${issueKey}: ${fromLabel ?? "Uncategorized"} → ${toLabel ?? "Uncategorized"}`
    );
  } catch (err) {
    showToast(`Couldn't update ${issueKey}: ${err.message}`, true);
  } finally {
    card.classList.remove("saving");
  }
}

// Board-level delegation for drag start/end + suppress click-after-drag navigation.
function wireBoardDnD() {
  boardEl.addEventListener("dragstart", (e) => {
    const card = e.target.closest(".card");
    if (card) onDragStart(card, e);
  });
  boardEl.addEventListener("dragend", (e) => {
    const card = e.target.closest(".card");
    if (card) onDragEnd(card);
  });
  // Suppress the click that can follow a drag so it doesn't open the Jira link.
  boardEl.addEventListener("click", (e) => {
    if (performance.now() - dragEndedAt < 250) e.preventDefault();
  });
}

/* ---------------- filtering ---------------- */

function applyFilter(term) {
  const q = term.trim().toLowerCase();
  for (const col of boardEl.querySelectorAll(".column")) {
    let visible = 0;
    for (const card of col.querySelectorAll(".card")) {
      const match = !q || card._search.includes(q);
      card.classList.toggle("hidden", !match);
      if (match) visible++;
    }
    col.classList.toggle("hidden", q && visible === 0);
  }
}

/* ---------------- add column ---------------- */

function addColumn(rawLabel) {
  const label = rawLabel.trim();
  if (!label) return;
  if (/\s/.test(label)) {
    showToast("Jira labels can't contain spaces.", true);
    return;
  }
  if (existingColumnLabels().has(label)) {
    showToast(`Column "${label}" already exists.`, true);
    return;
  }
  const col = makeColumn({ label, issues: [] });
  // Insert before the Uncategorized column if present, else at the end.
  const uncat = [...boardEl.querySelectorAll(".column")].find((c) => !labelOf(c));
  boardEl.insertBefore(col, uncat || null);
  col.scrollIntoView({ behavior: "smooth", inline: "end" });
}

/* ---------------- init ---------------- */

async function detectWriteMode() {
  try {
    const res = await fetch("/api/health", { cache: "no-store" });
    if (!res.ok) return false;
    const data = await res.json();
    return Boolean(data.write);
  } catch {
    return false; // e.g. on GitHub Pages there is no /api
  }
}

async function init() {
  editable = await detectWriteMode();

  try {
    const res = await fetch("board.json", { cache: "no-store" });
    if (!res.ok) throw new Error(`board.json not found (${res.status})`);
    const board = await res.json();

    const columns = board.columns.map((c) =>
      makeColumn({
        label: c.label,
        display: c.label,
        issues: c.issues,
        uncategorized: Boolean(c.uncategorized),
      })
    );
    boardEl.replaceChildren(...columns);

    if (board.generatedAt) {
      const d = new Date(board.generatedAt);
      updatedEl.textContent = `Updated ${d.toLocaleString()} · ${board.totalIssues} issues`;
    }

    searchEl.addEventListener("input", (e) => applyFilter(e.target.value));

    if (editable) {
      document.body.classList.add("editable");
      boardEl.classList.add("editable");
      editBadge.classList.remove("hidden");
      addColForm.classList.remove("hidden");
      wireBoardDnD();
      addColForm.addEventListener("submit", (e) => {
        e.preventDefault();
        addColumn(addColInput.value);
        addColInput.value = "";
      });
    }
  } catch (err) {
    boardEl.replaceChildren(
      el("div", { className: "error" }, [
        el("strong", { textContent: "Could not load board data. " }),
        el("span", {
          textContent:
            "Run `npm run build` to generate docs/board.json, then reload. " + err.message,
        }),
      ])
    );
  }
}

init();
